// Constants used throughout validation
let valid = true; 
const REQUIRED_KEYS = new Set(["priceLow", "priceHigh", "city", "caseType", "languages", "disabilityFocused", "description"]);
const invalidString = s => typeof s !== "string" || s.trim().length === 0;

// Get JSON to validate
const body = $input.first().json.body;

// Check if all fields are present
if ([...REQUIRED_KEYS].some(k => body[k] == null)) valid = false;
else if (!Object.keys(body).every(k => REQUIRED_KEYS.has(k))) valid = false;
else {
  // Extract all fields for individual validation checks
  const {priceLow, priceHigh, city, caseType, languages, disabilityFocused, description} = body;

  // Check if fields are valid
  if (
    !Number.isFinite(priceLow) ||
    !Number.isFinite(priceHigh) ||
    priceLow < 0 || 
    priceHigh < 0 || 
    priceLow > priceHigh
  ) valid = false;
  else if (invalidString(city)) valid = false;
  else if (invalidString(caseType)) valid = false;
  else if (
    !Array.isArray(languages) || 
    languages.some(lang => invalidString(lang))
  ) valid = false;
  else if (typeof disabilityFocused !== "boolean") valid = false;
  else if (invalidString(description)) valid = false;
}

// Return the body and the valid flag 
return [{json: {...body, valid}}];

